const STORAGE_KEY = "seer:announcements";

type SupportedLanguage = "zh" | "en";

type AnnouncementRecord = Record<SupportedLanguage, string>;

export const NOTICE_FALLBACKS: AnnouncementRecord = {
  zh: "SEER 测试网已上线，请使用 Sepolia 测试网体验",
  en: "SEER testnet is live. Please use the Sepolia testnet to explore.",
};

function canUseStorage() {
  return typeof globalThis !== "undefined" && typeof globalThis.localStorage !== "undefined";
}

function readStorage(): AnnouncementRecord {
  if (!canUseStorage()) {
    return { ...NOTICE_FALLBACKS };
  }

  try {
    const raw = globalThis.localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return { ...NOTICE_FALLBACKS };
    }

    const parsed = JSON.parse(raw) as Partial<AnnouncementRecord>;
    return {
      zh: typeof parsed.zh === "string" && parsed.zh.trim() ? parsed.zh.trim() : NOTICE_FALLBACKS.zh,
      en: typeof parsed.en === "string" && parsed.en.trim() ? parsed.en.trim() : NOTICE_FALLBACKS.en,
    };
  } catch {
    return { ...NOTICE_FALLBACKS };
  }
}

function writeStorage(value: AnnouncementRecord) {
  if (!canUseStorage()) {
    return;
  }

  globalThis.localStorage.setItem(STORAGE_KEY, JSON.stringify(value));
}

export function getAnnouncementContent(language: string) {
  const storage = readStorage();
  const normalized = language === "en" ? "en" : "zh";
  return storage[normalized];
}

export function saveAnnouncementContent(language: string, content: string, _adminAddress?: string) {
  const normalized = language === "en" ? "en" : "zh";
  const storage = readStorage();
  storage[normalized] = content.trim() || NOTICE_FALLBACKS[normalized];
  writeStorage(storage);
  return { success: true, language: normalized };
}
